class Solution:
    def getNumberOfBacklogOrders(self, orders):
        MOD = 1000000007
        # buys: dict price -> amount ; sells: dict price -> amount
        buys = {}
        sells = {}
        for price, amount, otype in orders:
            if otype == 0:
                # buy: match against cheapest sell <= price
                while amount > 0 and sells:
                    best = min(sells)
                    if best > price:
                        break
                    take = min(amount, sells[best])
                    amount -= take
                    sells[best] -= take
                    if sells[best] == 0:
                        del sells[best]
                if amount > 0:
                    buys[price] = buys.get(price, 0) + amount
            else:
                while amount > 0 and buys:
                    best = max(buys)
                    if best < price:
                        break
                    take = min(amount, buys[best])
                    amount -= take
                    buys[best] -= take
                    if buys[best] == 0:
                        del buys[best]
                if amount > 0:
                    sells[price] = sells.get(price, 0) + amount
        total = sum(buys.values()) + sum(sells.values())
        return total % MOD

