import heapq

class Solution:
    def getNumberOfBacklogOrders(self, orders):
        MOD = 1000000007
        buy = []   # max-heap via negative price: (-price, amount)
        sell = []  # min-heap: (price, amount)
        for price, amount, otype in orders:
            if otype == 0:
                while amount > 0 and sell and sell[0][0] <= price:
                    sp, sa = sell[0]
                    take = min(amount, sa)
                    amount -= take
                    sa -= take
                    if sa == 0:
                        heapq.heappop(sell)
                    else:
                        sell[0] = (sp, sa)
                if amount > 0:
                    heapq.heappush(buy, (-price, amount))
            else:
                while amount > 0 and buy and -buy[0][0] >= price:
                    bp, ba = buy[0]
                    take = min(amount, ba)
                    amount -= take
                    ba -= take
                    if ba == 0:
                        heapq.heappop(buy)
                    else:
                        buy[0] = (bp, ba)
                if amount > 0:
                    heapq.heappush(sell, (price, amount))
        total = sum(a for _, a in buy) + sum(a for _, a in sell)
        return total % MOD

