var getNumberOfBacklogOrders = function(orders) {
    const MOD = 1000000007n;
    // simple binary heaps
    const buy = [];  // max-heap by price; nodes {price, amount}
    const sell = []; // min-heap by price
    const up = (h, i, cmp) => {
        while (i > 0) {
            const p = (i - 1) >> 1;
            if (cmp(h[i], h[p]) < 0) { [h[i], h[p]] = [h[p], h[i]]; i = p; } else break;
        }
    };
    const down = (h, cmp) => {
        let i = 0; const n = h.length;
        while (true) {
            let s = i, l = 2 * i + 1, r = 2 * i + 2;
            if (l < n && cmp(h[l], h[s]) < 0) s = l;
            if (r < n && cmp(h[r], h[s]) < 0) s = r;
            if (s === i) break;
            [h[i], h[s]] = [h[s], h[i]]; i = s;
        }
    };
    const push = (h, node, cmp) => { h.push(node); up(h, h.length - 1, cmp); };
    const pop = (h, cmp) => { const top = h[0]; const last = h.pop(); if (h.length) { h[0] = last; down(h, cmp); } return top; };
    const buyCmp = (a, b) => b.price - a.price;  // max-heap on price
    const sellCmp = (a, b) => a.price - b.price; // min-heap on price
    for (const [price, amt, otype] of orders) {
        let amount = amt;
        if (otype === 0) {
            while (amount > 0 && sell.length && sell[0].price <= price) {
                const top = sell[0];
                const take = Math.min(amount, top.amount);
                amount -= take;
                top.amount -= take;
                if (top.amount === 0) pop(sell, sellCmp);
            }
            if (amount > 0) push(buy, { price, amount }, buyCmp);
        } else {
            while (amount > 0 && buy.length && buy[0].price >= price) {
                const top = buy[0];
                const take = Math.min(amount, top.amount);
                amount -= take;
                top.amount -= take;
                if (top.amount === 0) pop(buy, buyCmp);
            }
            if (amount > 0) push(sell, { price, amount }, sellCmp);
        }
    }
    let total = 0n;
    for (const node of buy) total += BigInt(node.amount);
    for (const node of sell) total += BigInt(node.amount);
    return Number(total % MOD);
};
